mapper.select:
SELECT CAST(relation_row.id AS CHAR) AS id, relation_row.merchant_id AS merchantId, merchant.shop_name AS merchantName, merchant.contact_name AS contactName, merchant.contact_phone AS contactPhone, ma.member_code AS merchantCode, relation_row.status AS status, DATE_FORMAT(relation_row.cooperation_start_at, '%Y-%m-%d %H:%i') AS cooperationStartAt, DATE_FORMAT(relation_row.cooperation_end_at, '%Y-%m-%d %H:%i') AS cooperationEndAt, relation_row.remark AS remark, DATE_FORMAT(relation_row.updated_time, '%Y-%m-%d %H:%i') AS updatedAt, ( SELECT COUNT(1) FROM supplier_goods_authorization auth_row WHERE auth_row.deleted = 0 AND auth_row.supplier_id = relation_row.supplier_id AND auth_row.merchant_id = relation_row.merchant_id AND auth_row.auth_status = 'ACTIVE' ) AS authorizedSkuCount, ( SELECT COUNT(1) FROM merchant_goods mg WHERE mg.deleted = 0 AND mg.supplier_id = relation_row.supplier_id AND mg.merchant_id = relation_row.merchant_id ) AS importedSkuCount FROM merchant_supplier_relation relation_row JOIN merchant_info merchant ON merchant.id = relation_row.merchant_id AND merchant.deleted = 0 JOIN member_account ma ON ma.id = merchant.member_id AND ma.deleted = 0 WHERE relation_row.deleted = 0 AND relation_row.supplier_id = #{supplierId}
AND relation_row.status = #{status}
ORDER BY relation_row.updated_time DESC, relation_row.id DESC LIMIT #{limit} OFFSET #{offset}
